SET NAMES utf8mb4;
SET CHARACTER SET utf8mb4;

-- ISMS-P 인증 항목 마스터 테이블
CREATE TABLE IF NOT EXISTS isms_items (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    item_code VARCHAR(20) NOT NULL UNIQUE,
    item_name VARCHAR(200) NOT NULL,
    domain_code VARCHAR(10) NOT NULL,
    domain_name VARCHAR(100) NOT NULL,
    section_num TINYINT NOT NULL,
    section_name VARCHAR(100) NOT NULL,
    description TEXT,
    sort_order INT NOT NULL DEFAULT 0
);

-- ISMS-P 증적 기록 테이블
CREATE TABLE IF NOT EXISTS isms_evidences (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    item_id BIGINT NOT NULL,
    year INT NOT NULL,
    title VARCHAR(500) NOT NULL,
    content TEXT,
    file_name VARCHAR(500),
    file_path VARCHAR(1000),
    status ENUM('COMPLIANT','PARTIAL','NON_COMPLIANT','NA') NOT NULL DEFAULT 'COMPLIANT',
    source_evidence_id BIGINT NULL COMMENT '참조 증적 ID (자기참조)',
    registrant_id BIGINT,
    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (item_id) REFERENCES isms_items(id) ON DELETE CASCADE,
    FOREIGN KEY (registrant_id) REFERENCES users(id) ON DELETE SET NULL,
    FOREIGN KEY (source_evidence_id) REFERENCES isms_evidences(id) ON DELETE SET NULL
);

