INSERT IGNORE INTO isms_items (item_code, item_name, domain_code, domain_name, section_num, section_name, description, sort_order) VALUES
('1.1.1','경영진의 참여','1.1','관리체계 기반 마련',1,'관리체계 수립 및 운영','최고경영자는 정보보호 및 개인정보보호 관리체계의 수립과 운영활동 전반에 경영진의 참여가 이루어질 수 있도록 보고 및 의사결정 체계를 수립하여 운영하여야 한다.',1),
('1.1.2','최고책임자의 지정','1.1','관리체계 기반 마련',1,'관리체계 수립 및 운영','최고경영자는 정보보호 업무를 총괄하는 정보보호 최고책임자와 개인정보보호 업무를 총괄하는 개인정보보호 책임자를 예산·인력 등 자원을 할당할 수 있는 임원급으로 지정하여야 한다.',2),
('1.1.3','조직 구성','1.1','관리체계 기반 마련',1,'관리체계 수립 및 운영','최고경영자는 정보보호와 개인정보보호의 효과적 구현을 위한 실무조직, 위원회, 협의체를 구성하여 운영하여야 한다.',3),
('1.1.4','범위 설정','1.1','관리체계 기반 마련',1,'관리체계 수립 및 운영','조직의 핵심 서비스와 개인정보 처리 현황 등을 고려하여 관리체계 범위를 설정하고 문서화하여야 한다.',4),
('1.1.5','정책 수립','1.1','관리체계 기반 마련',1,'관리체계 수립 및 운영','정보보호와 개인정보보호 정책 및 시행문서를 수립·작성하며 경영진 승인을 받고 임직원에게 전달하여야 한다.',5),
('1.1.6','자원 할당','1.1','관리체계 기반 마련',1,'관리체계 수립 및 운영','최고경영자는 전문 인력을 확보하고 관리체계의 효과적 구현을 위한 예산 및 자원을 할당하여야 한다.',6),
('1.2.1','정보자산 식별','1.2','위험 관리',1,'관리체계 수립 및 운영','정보자산 분류기준을 수립하여 모든 정보자산을 식별·분류하고, 중요도를 산정한 후 목록을 최신으로 관리하여야 한다.',7),
('1.2.2','현황 및 흐름분석','1.2','위험 관리',1,'관리체계 수립 및 운영','정보서비스 및 개인정보 처리 현황을 분석하고 업무 절차와 흐름을 파악하여 문서화하며 주기적으로 최신성을 유지하여야 한다.',8),
('1.2.3','위험 평가','1.2','위험 관리',1,'관리체계 수립 및 운영','유형별 위협정보를 수집하고 적합한 위험 평가 방법을 선정하여 연 1회 이상 위험을 평가하며, 수용 위험은 경영진 승인을 받아 관리하여야 한다.',9),
('1.2.4','보호대책 선정','1.2','위험 관리',1,'관리체계 수립 및 운영','식별된 위험을 처리하기 위하여 적합한 보호대책을 선정하고 이행계획을 수립하여 경영진의 승인을 받아야 한다.',10),
('1.3.1','보호대책 구현','1.3','관리체계 운영',1,'관리체계 수립 및 운영','선정한 보호대책은 이행계획에 따라 효과적으로 구현하고, 경영진은 이행결과의 정확성과 효과성을 확인하여야 한다.',11),
('1.3.2','보호대책 공유','1.3','관리체계 운영',1,'관리체계 수립 및 운영','보호대책을 운영할 부서 및 담당자를 파악하여 관련 내용을 공유하고 교육하여 지속적으로 운영되도록 하여야 한다.',12),
('1.3.3','운영현황 관리','1.3','관리체계 운영',1,'관리체계 수립 및 운영','운영활동 및 수행 내역을 식별 및 추적이 가능하도록 기록하여 관리하고, 경영진은 주기적으로 효과성을 확인하여야 한다.',13),
('1.4.1','법적 요구사항 준수 검토','1.4','관리체계 점검 및 개선',1,'관리체계 수립 및 운영','정보보호 및 개인정보보호 관련 법적 요구사항을 주기적으로 파악하여 규정에 반영하고 준수 여부를 지속적으로 검토하여야 한다.',14),
('1.4.2','관리체계 점검','1.4','관리체계 점검 및 개선',1,'관리체계 수립 및 운영','관리체계가 효과적으로 운영되고 있는지 연 1회 이상 점검하고, 발견된 문제점을 경영진에게 보고하여야 한다.',15),
('1.4.3','관리체계 개선','1.4','관리체계 점검 및 개선',1,'관리체계 수립 및 운영','식별된 관리체계 문제점의 원인을 분석하고 재발방지 대책을 수립·이행하며, 경영진은 개선 결과를 확인하여야 한다.',16),
('2.1.1','정책의 유지관리','2.1','정책, 조직, 자산 관리',2,'보호대책 요구사항','정보보호 관련 정책과 시행문서는 주기적으로 검토하여 필요한 경우 제·개정하고 그 내역을 이력관리하여야 한다.',17),
('2.1.2','조직의 유지관리','2.1','정책, 조직, 자산 관리',2,'보호대책 요구사항','각 구성원에게 정보보호 역할 및 책임을 할당하고 상호 의사소통 체계를 수립하여 운영하여야 한다.',18),
('2.1.3','정보자산 관리','2.1','정책, 조직, 자산 관리',2,'보호대책 요구사항','정보자산의 용도와 중요도에 따른 취급 절차 및 보호대책을 수립·이행하고 자산별 책임소재를 명확히 정의하여야 한다.',19),
('2.2.1','주요 직무자 지정 및 관리','2.2','인적 보안',2,'보호대책 요구사항','주요 직무의 기준과 관리방안을 수립하고, 주요 직무자를 최소한으로 지정하여 그 목록을 최신으로 관리하여야 한다.',20),
('2.2.2','직무 분리','2.2','인적 보안',2,'보호대책 요구사항','권한 오·남용으로 인한 피해 예방을 위하여 직무 분리 기준을 수립하고 적용하여야 한다.',21),
('2.2.3','보안 서약','2.2','인적 보안',2,'보호대책 요구사항','정보자산을 취급하거나 접근권한이 부여된 임직원·외부자 등이 준수사항을 명확히 인지할 수 있도록 보안 서약을 받아야 한다.',22),
('2.2.4','인식제고 및 교육훈련','2.2','인적 보안',2,'보호대책 요구사항','연간 인식제고 활동 및 교육훈련 계획을 수립·운영하고, 그 결과에 따른 효과성을 평가하여 다음 계획에 반영하여야 한다.',23),
('2.2.5','퇴직 및 직무변경 관리','2.2','인적 보안',2,'보호대책 요구사항','퇴직 및 직무변경 시 자산반납, 계정 및 접근권한 회수·조정, 결과확인 등의 절차를 수립·관리하여야 한다.',24),
('2.2.6','보안 위반 시 조치','2.2','인적 보안',2,'보호대책 요구사항','임직원 및 관련 외부자가 법령, 규제 및 내부정책을 위반한 경우 이에 따른 조치 절차를 수립·이행하여야 한다.',25),
('2.3.1','외부자 현황 관리','2.3','외부자 보안',2,'보호대책 요구사항','업무를 외부에 위탁하거나 외부 서비스를 이용하는 경우 그 현황을 식별하고 위험을 파악하여 적절한 보호대책을 마련하여야 한다.',26),
('2.3.2','외부자 계약 시 보안','2.3','외부자 보안',2,'보호대책 요구사항','외부자에게 업무를 위탁하는 경우 정보보호 요구사항을 식별하고 계약서 등에 명시하여야 한다.',27),
('2.3.3','외부자 보안 이행 관리','2.3','외부자 보안',2,'보호대책 요구사항','외부자의 보호대책 이행 여부를 주기적인 점검 또는 감사 등으로 관리·감독하여야 한다.',28),
('2.3.4','외부자 계약 변경 및 만료 시 보안','2.3','외부자 보안',2,'보호대책 요구사항','외부자 계약만료, 업무종료, 담당자 변경 시에는 정보자산 반납, 접근계정 삭제, 중요정보 파기 등의 보호대책을 이행하여야 한다.',29),
('2.4.1','보호구역 지정','2.4','물리 보안',2,'보호대책 요구사항','물리적·환경적 위협으로부터 보호하기 위하여 통제구역·제한구역·접견구역 등 물리적 보호구역을 지정하고 각 구역별 보호대책을 수립·이행하여야 한다.',30),
('2.4.2','출입통제','2.4','물리 보안',2,'보호대책 요구사항','보호구역은 인가된 사람만이 출입하도록 통제하고 출입 및 접근 이력을 주기적으로 검토하여야 한다.',31),
('2.4.3','정보시스템 보호','2.4','물리 보안',2,'보호대책 요구사항','정보시스템은 환경적 위협과 유해요소를 감소시킬 수 있도록 배치하고, 통신 및 전력 케이블이 손상을 입지 않도록 보호하여야 한다.',32),
('2.4.4','보호설비 운영','2.4','물리 보안',2,'보호대책 요구사항','정보시스템의 중요도 및 특성에 따라 온도·습도 조절, 화재감지, 소화설비, UPS, 비상발전기 등의 보호설비를 갖추고 운영하여야 한다.',33),
('2.4.5','보호구역 내 작업','2.4','물리 보안',2,'보호대책 요구사항','보호구역 내에서의 비인가행위 및 권한 오·남용을 방지하기 위한 작업 절차를 수립·이행하고 작업 기록을 주기적으로 검토하여야 한다.',34),
('2.4.6','반출입 기기 통제','2.4','물리 보안',2,'보호대책 요구사항','보호구역 내 정보시스템, 모바일 기기, 저장매체 등에 대한 반출입 통제절차를 수립·이행하고 주기적으로 검토하여야 한다.',35),
('2.4.7','업무환경 보안','2.4','물리 보안',2,'보호대책 요구사항','공용 사무용 기기 및 개인 업무환경을 통해 중요정보가 비인가자에게 노출되지 않도록 클린데스크, 정기점검 등 보호대책을 수립·이행하여야 한다.',36),
('2.5.1','사용자 계정 관리','2.5','인증 및 권한관리',2,'보호대책 요구사항','비인가 접근을 통제하고 접근권한을 최소한으로 부여할 수 있도록 사용자 등록·해지 및 접근권한 관리 절차를 수립·이행하여야 한다.',37),
('2.5.2','사용자 식별','2.5','인증 및 권한관리',2,'보호대책 요구사항','사용자 계정은 사용자별로 유일하게 구분할 수 있도록 식별자를 할당하고 추측 가능한 식별자 사용을 제한하여야 한다.',38),
('2.5.3','사용자 인증','2.5','인증 및 권한관리',2,'보호대책 요구사항','사용자의 접근은 안전한 인증절차와 강화된 인증방식을 적용하고 로그인 횟수 제한 등 비인가자 접근 통제방안을 수립·이행하여야 한다.',39),
('2.5.4','비밀번호 관리','2.5','인증 및 권한관리',2,'보호대책 요구사항','법적 요구사항, 외부 위협요인 등을 고려하여 비밀번호 관리절차를 수립·이행하여야 한다.',40),
('2.5.5','특수 계정 및 권한 관리','2.5','인증 및 권한관리',2,'보호대책 요구사항','특수 목적을 위하여 사용하는 계정 및 권한은 최소한으로 부여하고 별도로 식별하여 통제하여야 한다.',41),
('2.5.6','접근권한 검토','2.5','인증 및 권한관리',2,'보호대책 요구사항','사용자 계정의 등록·이용·삭제 및 접근권한의 부여·변경·삭제 이력을 남기고 주기적으로 검토하여 적정성을 점검하여야 한다.',42),
('2.6.1','네트워크 접근','2.6','접근통제',2,'보호대책 요구사항','비인가 접근을 통제하기 위하여 IP관리, 단말인증 등 관리절차를 수립·이행하고, 업무목적 및 중요도에 따라 네트워크 분리와 접근통제를 적용하여야 한다.',43),
('2.6.2','정보시스템 접근','2.6','접근통제',2,'보호대책 요구사항','정보시스템에 접근을 허용하는 사용자, 접근제한 방식, 안전한 접근수단 등을 정의하여 통제하여야 한다.',44),
('2.6.3','응용프로그램 접근','2.6','접근통제',2,'보호대책 요구사항','사용자별 업무 및 접근 정보의 중요도에 따라 응용프로그램 접근권한을 제한하고 중요정보 노출을 최소화하여야 한다.',45),
('2.6.4','데이터베이스 접근','2.6','접근통제',2,'보호대책 요구사항','데이터베이스 내 정보를 식별하고, 정보의 중요도와 사용자 유형에 따른 접근통제 정책을 수립·이행하여야 한다.',46),
('2.6.5','무선 네트워크 접근','2.6','접근통제',2,'보호대책 요구사항','무선 네트워크 사용 시 사용자 인증, 데이터 암호화, AP 통제 등 무선 네트워크 보호대책을 적용하여야 한다.',47),
('2.6.6','원격접근 통제','2.6','접근통제',2,'보호대책 요구사항','불가피한 사유로 원격접근을 허용하는 경우 책임자 승인, 접근 단말 지정, 강화된 인증, 구간 암호화 등 보호대책을 수립·이행하여야 한다.',48),
('2.6.7','인터넷 접속 통제','2.6','접근통제',2,'보호대책 요구사항','정보 유출, 악성코드 감염, 내부망 침투 등을 예방하기 위하여 인터넷 접속 통제 정책을 수립·이행하여야 한다.',49),
('2.7.1','암호정책 적용','2.7','암호화 적용',2,'보호대책 요구사항','법적 요구사항을 반영한 암호화 대상, 암호 강도, 암호 사용 정책을 수립하고 개인정보 및 주요정보의 저장·전송 시 암호화를 적용하여야 한다.',50),
('2.7.2','암호키 관리','2.7','암호화 적용',2,'보호대책 요구사항','암호키의 안전한 생성·이용·보관·배포·파기를 위한 관리 절차를 수립·이행하고, 필요 시 복구방안을 마련하여야 한다.',51),
('2.8.1','보안 요구사항 정의','2.8','정보시스템 도입 및 개발 보안',2,'보호대책 요구사항','정보시스템의 도입·개발·변경 시 법적 요구사항, 최신 보안취약점, 안전한 코딩방법 등 보안 요구사항을 정의하고 적용하여야 한다.',52),
('2.8.2','보안 요구사항 검토 및 시험','2.8','정보시스템 도입 및 개발 보안',2,'보호대책 요구사항','보안 요구사항에 따라 정보시스템이 도입 또는 구현되었는지 검토하기 위하여 검토 기준과 절차를 수립·이행하고 발견된 문제점에 대한 개선조치를 수행하여야 한다.',53),
('2.8.3','시험과 운영 환경 분리','2.8','정보시스템 도입 및 개발 보안',2,'보호대책 요구사항','개발 및 시험 시스템은 운영시스템에 대한 비인가 접근 및 변경의 위험을 감소시키기 위하여 원칙적으로 분리하여야 한다.',54),
('2.8.4','시험 데이터 보안','2.8','정보시스템 도입 및 개발 보안',2,'보호대책 요구사항','시험 과정에서 운영데이터의 유출을 예방하기 위하여 시험 데이터의 생성·이용·관리·파기에 관한 절차를 수립·이행하여야 한다.',55),
('2.8.5','소스 프로그램 관리','2.8','정보시스템 도입 및 개발 보안',2,'보호대책 요구사항','소스 프로그램은 인가된 사용자만이 접근할 수 있도록 관리하고, 운영환경에 보관하지 않는 것을 원칙으로 하여야 한다.',56),
('2.8.6','운영환경 이관','2.8','정보시스템 도입 및 개발 보안',2,'보호대책 요구사항','신규 도입·개발 또는 변경된 시스템을 운영환경으로 이관할 때는 통제된 절차를 따라야 한다.',57),
('2.9.1','변경관리','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','정보시스템 관련 자산의 모든 변경내역을 관리할 수 있도록 절차를 수립·이행하고, 변경 전 시스템의 성능 및 보안에 미치는 영향을 분석하여야 한다.',58),
('2.9.2','성능 및 장애관리','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','정보시스템의 가용성 보장을 위하여 성능 및 용량 요구사항을 정의하고 모니터링하여야 하며, 장애 발생 시 탐지·기록·분석·복구·보고 등의 절차를 수립·관리하여야 한다.',59),
('2.9.3','백업 및 복구관리','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','정보시스템의 가용성과 데이터 무결성을 유지하기 위하여 백업 대상, 주기, 방법, 보관장소, 보관기간, 소산 등의 절차를 수립·이행하여야 한다.',60),
('2.9.4','로그 및 접속기록 관리','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','정보시스템에 대한 사용자 접속기록, 시스템로그, 권한부여 내역 등의 로그유형, 보존기간, 보존방법 등을 정하고 안전하게 보존·관리하여야 한다.',61),
('2.9.5','로그 및 접속기록 점검','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','접근 및 사용에 대한 로그 검토기준을 수립하여 주기적으로 점검하며, 문제 발생 시 사후조치를 적시에 수행하여야 한다.',62),
('2.9.6','시간 동기화','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','로그 및 접속기록의 정확성을 보장하기 위하여 관련 정보시스템의 시각을 표준시각으로 동기화하고 주기적으로 관리하여야 한다.',63),
('2.9.7','정보자산의 재사용 및 폐기','2.9','시스템 및 서비스 운영관리',2,'보호대책 요구사항','정보자산의 재사용과 폐기 과정에서 개인정보 및 중요정보가 복구·재생되지 않도록 안전한 재사용 및 폐기 절차를 수립·이행하여야 한다.',64),
('2.10.1','보안시스템 운영','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','보안시스템 유형별로 관리자 지정, 최신 정책 업데이트, 룰셋 변경, 이벤트 모니터링 등의 운영절차를 수립·이행하고 보안시스템별 정책적용 현황을 관리하여야 한다.',65),
('2.10.2','클라우드 보안','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','클라우드 서비스 이용 시 서비스 유형에 따른 비인가 접근, 설정 오류 등에 따라 중요정보가 유출되지 않도록 보호대책을 수립·이행하여야 한다.',66),
('2.10.3','공개서버 보안','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','외부 네트워크에 공개되는 서버의 경우 내부 네트워크와 분리하고 강화된 보호대책을 수립·이행하여야 한다.',67),
('2.10.4','전자거래 및 핀테크 보안','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','전자거래 및 핀테크 서비스 제공 시 침해사고 예방을 위해 인증·암호화 등의 보호대책을 수립하고, 외부 시스템과 연계할 경우 안전성을 점검하여야 한다.',68),
('2.10.5','정보전송 보안','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','타 조직에 개인정보 및 중요정보를 전송할 경우 안전한 전송 정책을 수립하고 기술적 보호조치 등을 협약하고 이행하여야 한다.',69),
('2.10.6','업무용 단말기기 보안','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','PC, 모바일 기기 등 단말기기를 업무 목적으로 네트워크에 연결할 경우 기기 인증 및 보안설정 등의 접근통제 대책을 수립하고 주기적으로 점검하여야 한다.',70),
('2.10.7','보조저장매체 관리','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','보조저장매체를 통한 정보 유출이나 악성코드 감염을 방지하기 위한 관리 절차를 수립·이행하고, 중요정보가 포함된 보조저장매체는 안전한 장소에 보관하여야 한다.',71),
('2.10.8','패치관리','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','소프트웨어, 운영체제, 보안시스템 등의 취약점으로 인한 침해사고를 예방하기 위하여 최신 패치를 적용하여야 한다.',72),
('2.10.9','악성코드 통제','2.10','시스템 및 서비스 보안관리',2,'보호대책 요구사항','악성코드로부터 개인정보 및 중요정보, 정보시스템 등을 보호하기 위하여 악성코드 예방·탐지·대응 등의 보호대책을 수립·이행하여야 한다.',73),
('2.11.1','사고 예방 및 대응체계 구축','2.11','사고 예방 및 대응',2,'보호대책 요구사항','침해사고 및 개인정보 유출 등을 예방하고 사고 발생 시 신속하게 대응할 수 있도록 침해시도의 탐지·대응·분석 및 공유를 위한 체계와 절차를 수립하여야 한다.',74),
('2.11.2','취약점 점검 및 조치','2.11','사고 예방 및 대응',2,'보호대책 요구사항','정기적으로 취약점 점검을 수행하고 발견된 취약점에 대해서는 신속하게 조치하여야 한다. 또한 최신 보안취약점의 발생 여부를 지속적으로 파악하여 조치하여야 한다.',75),
('2.11.3','이상행위 분석 및 모니터링','2.11','사고 예방 및 대응',2,'보호대책 요구사항','침해시도, 개인정보유출 시도, 부정행위 등을 신속하게 탐지·대응할 수 있도록 네트워크 및 데이터 흐름을 수집하여 분석하여야 한다.',76),
('2.11.4','사고 대응 훈련 및 개선','2.11','사고 예방 및 대응',2,'보호대책 요구사항','사고 대응 절차를 숙지하도록 시나리오에 따른 모의훈련을 연 1회 이상 실시하고 훈련결과를 반영하여 대응체계를 개선하여야 한다.',77),
('2.11.5','사고 대응 및 복구','2.11','사고 예방 및 대응',2,'보호대책 요구사항','침해사고 및 개인정보 유출 징후나 발생을 인지한 때에는 법적 통지 및 신고 의무를 준수하며, 절차에 따라 신속하게 대응 및 복구하고 재발방지 대책을 수립하여야 한다.',78),
('2.12.1','재해·재난 대비 안전조치','2.12','재해복구',2,'보호대책 요구사항','핵심 서비스 및 시스템의 운영 연속성을 위협할 수 있는 재해 유형을 식별하고 영향을 분석하여야 한다. 또한 복구 목표시간, 복구 목표시점을 정의하고 재해 복구체계를 구축하여야 한다.',79),
('2.12.2','재해 복구 시험 및 개선','2.12','재해복구',2,'보호대책 요구사항','재해 복구 전략 및 대책의 적정성을 정기적으로 시험하여 시험결과 및 환경변화를 반영하여 복구전략 및 대책을 보완하여야 한다.',80);
INSERT IGNORE INTO isms_items (item_code, item_name, domain_code, domain_name, section_num, section_name, description, sort_order) VALUES
('3.1.1','개인정보 수집∙이용','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보는 적법하고 정당하게 수집∙이용하여야 하며, 정보주체의 동의를 근거로 수집하는 경우에는 적법한 방법으로 정보주체의 동의를 받아야 한다. 또한 만 14세 미만 아동의 개인정보를 수집하는 경우에는 그 법정대리인의 동의를 받아야 하며 법정대리인이 동의하였는지를 확인하여야 한다.',81),
('3.1.2','개인정보 수집 제한','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보를 수집하는 경우 처리 목적에 필요한 최소한의 개인정보만을 수집하여야 하며, 정보주체가 선택적으로 동의할 수 있는 사항 등에 동의하지 아니한다는 이유로 정보주체에게 재화 또는 서비스의 제공을 거부하지 않아야 한다.',82),
('3.1.3','주민등록번호 처리 제한','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','주민등록번호는 법적 근거가 있는 경우를 제외하고는 수집∙이용 등 처리할 수 없으며, 주민등록번호의 처리가 허용된 경우라 하더라도 인터넷 홈페이지 등에서 대체수단을 제공하여야 한다.',83),
('3.1.4','민감정보 및 고유식별정보의 처리 제한','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','민감정보와 고유식별정보(주민등록번호 제외)를 처리하기 위해서는 법령에서 구체적으로 처리를 요구하거나 허용하는 경우를 제외하고는 정보주체의 별도 동의를 받아야 한다.',84),
('3.1.5','개인정보 간접수집','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','정보주체 이외로부터 개인정보를 수집하거나 제3자로부터 제공받는 경우에는 업무에 필요한 최소한의 개인정보를 수집하거나 제공받아야 하며, 법령에 근거하거나 정보주체의 요구가 있으면 개인정보의 수집 출처, 처리목적, 처리정지의 요구권리를 알려야 한다.',85),
('3.1.6','영상정보처리기기 설치∙운영','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','고정형 영상정보처리기기를 공개된 장소에 설치∙운영하거나 이동형 영상정보처리기기를 공개된 장소에서 업무를 목적으로 운영하는 경우 설치 목적 및 위치에 따라 법적 요구사항을 준수하고, 적절한 보호대책을 수립∙이행하여야 한다.',86),
('3.1.7','마케팅 목적의 개인정보 수집∙이용','3.1','개인정보 수집 시 보호조치',3,'개인정보 처리단계별 요구사항','재화나 서비스의 홍보, 판매 권유, 광고성 정보전송 등 마케팅 목적으로 개인정보를 수집∙이용하는 경우 그 목적을 정보주체가 명확하게 인지할 수 있도록 고지하고 동의를 받아야 한다.',87),
('3.2.1','개인정보 현황관리','3.2','개인정보 보유 및 이용 시 보호조치',3,'개인정보 처리단계별 요구사항','수집∙보유하는 개인정보의 항목, 보유량, 처리 목적 및 방법, 보유기간 등 현황을 정기적으로 관리하여야 하며, 공공기관의 경우 이를 법률에서 정한 관계기관의 장에게 등록하여야 한다.',88),
('3.2.2','개인정보 품질보장','3.2','개인정보 보유 및 이용 시 보호조치',3,'개인정보 처리단계별 요구사항','수집된 개인정보는 처리 목적에 필요한 범위에서 개인정보의 정확성∙완전성∙최신성이 보장되도록 정보주체에게 관리절차를 제공하여야 한다.',89),
('3.2.3','이용자 단말기 접근 보호','3.2','개인정보 보유 및 이용 시 보호조치',3,'개인정보 처리단계별 요구사항','정보주체(이용자)의 이동통신단말장치 내에 저장되어 있는 정보 및 이동통신단말장치에 설치된 기능에 접근이 필요한 경우 이를 명확하게 인지할 수 있도록 알리고 정보주체(이용자)의 동의를 받아야 한다.',90),
('3.2.4','개인정보 목적 외 이용 및 제공','3.2','개인정보 보유 및 이용 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보는 수집 시의 정보주체에게 고지∙동의를 받은 목적 또는 법령에 근거한 범위 내에서만 이용 또는 제공하여야 하며, 이를 초과하여 이용∙제공하려는 때에는 정보주체의 추가 동의를 받거나 관계 법령에 따른 적법한 경우인지 확인하고 적절한 보호대책을 수립∙이행하여야 한다.',91),
('3.2.5','가명정보 처리','3.2','개인정보 보유 및 이용 시 보호조치',3,'개인정보 처리단계별 요구사항','가명정보를 처리하는 경우 목적제한, 결합제한, 안전조치, 금지의무 등 법적 요건을 준수하고 적정 수준의 가명처리를 보장할 수 있도록 가명처리 절차를 수립∙이행하여야 한다.',92),
('3.3.1','개인정보 제3자 제공','3.3','개인정보 제공 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보를 제3자에게 제공하는 경우 법적 근거에 의하거나 정보주체의 동의를 받아야 하며, 제3자에게 개인정보의 접근을 허용하는 등 제공 과정에서 개인정보를 안전하게 보호하기 위한 보호대책을 수립∙이행하여야 한다.',93),
('3.3.2','개인정보 처리 업무 위탁','3.3','개인정보 제공 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보 처리업무를 제3자에게 위탁하는 경우 위탁하는 업무의 내용과 수탁자 등 관련사항을 공개하여야 한다. 또한 재화 또는 서비스를 홍보하거나 판매를 권유하는 업무를 위탁하는 경우 위탁하는 업무의 내용과 수탁자를 정보주체에게 알려야 한다.',94),
('3.3.3','영업의 양도 등에 따른 개인정보 이전','3.3','개인정보 제공 시 보호조치',3,'개인정보 처리단계별 요구사항','영업의 양도∙합병 등으로 개인정보를 이전하거나 이전받는 경우 정보주체 통지 등 적절한 보호조치를 수립∙이행하여야 한다.',95),
('3.3.4','개인정보 국외이전','3.3','개인정보 제공 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보를 국외로 이전하는 경우 국외 이전에 대한 동의, 관련 사항에 대한 공개 등 적절한 보호조치를 수립∙이행하여야 한다.',96),
('3.4.1','개인정보 파기','3.4','개인정보 파기 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보의 보유기간 및 파기 관련 내부 정책을 수립하고 개인정보의 보유기간 경과, 처리목적 달성 등 파기 시점이 도달한 때에는 파기의 안전성 및 완전성이 보장될 수 있는 방법으로 지체 없이 파기하여야 한다.',97),
('3.4.2','처리목적 달성 후 보유 시 조치','3.4','개인정보 파기 시 보호조치',3,'개인정보 처리단계별 요구사항','개인정보의 보유기간 경과 또는 처리목적 달성 후에도 관련 법령 등에 따라 파기하지 아니하고 보존하는 경우에는 해당 목적에 필요한 최소한의 항목으로 제한하고 다른 개인정보와 분리하여 저장∙관리하여야 한다.',98),
('3.5.1','개인정보 처리방침 공개','3.5','정보주체 권리보호',3,'개인정보 처리단계별 요구사항','개인정보의 처리 목적 등 필요한 사항을 모두 포함하여 정보주체가 알기 쉽도록 개인정보 처리방침을 수립하고, 이를 정보주체가 언제든지 쉽게 확인할 수 있도록 적절한 방법에 따라 공개하고 지속적으로 현행화하여야 한다.',99),
('3.5.2','정보주체 권리보장','3.5','정보주체 권리보호',3,'개인정보 처리단계별 요구사항','정보주체가 개인정보의 열람, 정정∙삭제, 처리정지, 이의제기, 동의철회 등 요구를 수집 방법∙절차보다 쉽게 할 수 있도록 권리행사 방법 및 절차를 수립∙이행하고, 정보주체의 요구를 받은 경우 지체 없이 처리하고 관련 기록을 남겨야 한다. 또한 정보주체의 사생활 침해, 명예훼손 등 타인의 권리를 침해하는 정보가 유통되지 않도록 삭제 요청, 임시조치 등의 기준을 수립∙이행하여야 한다.',100),
('3.5.3','정보주체에 대한 통지','3.5','정보주체 권리보호',3,'개인정보 처리단계별 요구사항','개인정보의 이용∙제공 내역 등 정보주체에게 통지하여야 할 사항을 파악하여 그 내용을 주기적으로 통지하여야 한다.',101);
